  begin;
    
        
            
                
                
            
                
                
            
        
    

    

    merge into OLIST_DW.MARTS.fct_orders as DBT_INTERNAL_DEST
        using OLIST_DW.MARTS.fct_orders__dbt_tmp as DBT_INTERNAL_SOURCE
        on (
                    DBT_INTERNAL_SOURCE.order_id = DBT_INTERNAL_DEST.order_id
                ) and (
                    DBT_INTERNAL_SOURCE.order_item_id = DBT_INTERNAL_DEST.order_item_id
                )

    
    when matched then update set
        "ORDER_ID" = DBT_INTERNAL_SOURCE."ORDER_ID","ORDER_ITEM_ID" = DBT_INTERNAL_SOURCE."ORDER_ITEM_ID","CUSTOMER_ID" = DBT_INTERNAL_SOURCE."CUSTOMER_ID","SELLER_ID" = DBT_INTERNAL_SOURCE."SELLER_ID","PRODUCT_ID" = DBT_INTERNAL_SOURCE."PRODUCT_ID","CUSTOMER_CITY" = DBT_INTERNAL_SOURCE."CUSTOMER_CITY","CUSTOMER_STATE" = DBT_INTERNAL_SOURCE."CUSTOMER_STATE","CUSTOMER_SEGMENT" = DBT_INTERNAL_SOURCE."CUSTOMER_SEGMENT","PRODUCT_CATEGORY" = DBT_INTERNAL_SOURCE."PRODUCT_CATEGORY","PRODUCT_REVENUE_TIER" = DBT_INTERNAL_SOURCE."PRODUCT_REVENUE_TIER","SELLER_CITY" = DBT_INTERNAL_SOURCE."SELLER_CITY","SELLER_STATE" = DBT_INTERNAL_SOURCE."SELLER_STATE","SELLER_TIER" = DBT_INTERNAL_SOURCE."SELLER_TIER","ORDER_STATUS" = DBT_INTERNAL_SOURCE."ORDER_STATUS","ORDER_PURCHASE_TIMESTAMP" = DBT_INTERNAL_SOURCE."ORDER_PURCHASE_TIMESTAMP","ORDER_APPROVED_AT" = DBT_INTERNAL_SOURCE."ORDER_APPROVED_AT","ORDER_DELIVERED_CARRIER_DATE" = DBT_INTERNAL_SOURCE."ORDER_DELIVERED_CARRIER_DATE","ORDER_DELIVERED_CUSTOMER_DATE" = DBT_INTERNAL_SOURCE."ORDER_DELIVERED_CUSTOMER_DATE","ORDER_ESTIMATED_DELIVERY_DATE" = DBT_INTERNAL_SOURCE."ORDER_ESTIMATED_DELIVERY_DATE","SHIPPING_LIMIT_DATE" = DBT_INTERNAL_SOURCE."SHIPPING_LIMIT_DATE","ORDER_YEAR_MONTH" = DBT_INTERNAL_SOURCE."ORDER_YEAR_MONTH","ITEM_PRICE" = DBT_INTERNAL_SOURCE."ITEM_PRICE","FREIGHT_VALUE" = DBT_INTERNAL_SOURCE."FREIGHT_VALUE","ORDER_ITEM_REVENUE" = DBT_INTERNAL_SOURCE."ORDER_ITEM_REVENUE","TOTAL_PAYMENT_VALUE" = DBT_INTERNAL_SOURCE."TOTAL_PAYMENT_VALUE","MAX_INSTALLMENTS" = DBT_INTERNAL_SOURCE."MAX_INSTALLMENTS","PAYMENT_TYPES" = DBT_INTERNAL_SOURCE."PAYMENT_TYPES","AVG_REVIEW_SCORE" = DBT_INTERNAL_SOURCE."AVG_REVIEW_SCORE","DELIVERY_DAYS" = DBT_INTERNAL_SOURCE."DELIVERY_DAYS","IS_LATE_DELIVERY" = DBT_INTERNAL_SOURCE."IS_LATE_DELIVERY","ORDER_MONTH" = DBT_INTERNAL_SOURCE."ORDER_MONTH","ORDER_QUARTER" = DBT_INTERNAL_SOURCE."ORDER_QUARTER","ORDER_YEAR" = DBT_INTERNAL_SOURCE."ORDER_YEAR","UPDATED_AT" = DBT_INTERNAL_SOURCE."UPDATED_AT"
    

    when not matched then insert
        ("ORDER_ID", "ORDER_ITEM_ID", "CUSTOMER_ID", "SELLER_ID", "PRODUCT_ID", "CUSTOMER_CITY", "CUSTOMER_STATE", "CUSTOMER_SEGMENT", "PRODUCT_CATEGORY", "PRODUCT_REVENUE_TIER", "SELLER_CITY", "SELLER_STATE", "SELLER_TIER", "ORDER_STATUS", "ORDER_PURCHASE_TIMESTAMP", "ORDER_APPROVED_AT", "ORDER_DELIVERED_CARRIER_DATE", "ORDER_DELIVERED_CUSTOMER_DATE", "ORDER_ESTIMATED_DELIVERY_DATE", "SHIPPING_LIMIT_DATE", "ORDER_YEAR_MONTH", "ITEM_PRICE", "FREIGHT_VALUE", "ORDER_ITEM_REVENUE", "TOTAL_PAYMENT_VALUE", "MAX_INSTALLMENTS", "PAYMENT_TYPES", "AVG_REVIEW_SCORE", "DELIVERY_DAYS", "IS_LATE_DELIVERY", "ORDER_MONTH", "ORDER_QUARTER", "ORDER_YEAR", "UPDATED_AT")
    values
